import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { searchRentals, fetchStates, fetchPropertyTypes } from '../utils/api';
import { LoadingState, ErrorState, EmptyState } from '../components/LoadingState';
import Pagination from '../components/Pagination';

/* =========================
   PRICE FORMAT
========================= */
const formatPrice = (p) =>
  p != null ? `$${Number(p).toLocaleString('en-AU')}/wk` : 'â€”';

/* =========================
   REVERSE GEOCODING
========================= */
const getAddressFromCoords = async (lat, lng) => {
  try {
    const res = await fetch(
      `https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lng}`
    );
    const data = await res.json();
    return data.display_name || 'Unknown location';
  } catch {
    return 'Unknown location';
  }
};

const SearchPage = () => {
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();

  const [states, setStates] = useState([]);
  const [propertyTypes, setPropertyTypes] = useState([]);

  /* =========================
     FILTER STATE (UNCHANGED UI KEYS)
  ========================= */
  const [filters, setFilters] = useState({
    state: searchParams.get('state') || '',
    suburb: searchParams.get('suburb') || '',
    postcode: searchParams.get('postcode') || '',
    propertyType: searchParams.get('propertyType') || '',
    min_price: searchParams.get('min_price') || '',
    max_price: searchParams.get('max_price') || '',
    bedrooms: searchParams.get('bedrooms') || '',
    bathrooms: searchParams.get('bathrooms') || '',
    parkingSpaces: searchParams.get('parkingSpaces') || '',
  });

  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [page, setPage] = useState(Number(searchParams.get('page')) || 1);

  const [addressCache, setAddressCache] = useState({});
  const debounceRef = useRef(null);

  useEffect(() => {
    fetchStates().then(setStates).catch(() => {});
    fetchPropertyTypes().then(setPropertyTypes).catch(() => {});
  }, []);

  /* =========================
     âś… FIXED SEARCH LOGIC
  ========================= */
  const doSearch = useCallback(async (currentFilters, currentPage) => {
    setLoading(true);
    setError(null);

    try {
      // đź”Ą IMPORTANT: map frontend -> backend keys properly
      const params = {
        page: currentPage,

        state: currentFilters.state,
        suburb: currentFilters.suburb,
        postcode: currentFilters.postcode,

        propertyType: currentFilters.propertyType,
        parkingSpaces: currentFilters.parkingSpaces,

        // numeric filters
        minPrice: currentFilters.min_price,
        maxPrice: currentFilters.max_price,
        bedrooms: currentFilters.bedrooms,
        bathrooms: currentFilters.bathrooms,
      };

      // remove empty
      Object.keys(params).forEach((k) => {
        if (params[k] === '' || params[k] == null) delete params[k];
      });

      const data = await searchRentals(params);
      setResults(data);
    } catch (err) {
      setError(err.message || 'Search failed.');
    } finally {
      setLoading(false);
    }
  }, []);

  /* =========================
     DEBOUNCE
  ========================= */
  useEffect(() => {
    if (debounceRef.current) clearTimeout(debounceRef.current);

    debounceRef.current = setTimeout(() => {
      doSearch(filters, page);

      const params = {};
      Object.entries(filters).forEach(([k, v]) => {
        if (v) params[k] = v;
      });

      if (page > 1) params.page = page;
      setSearchParams(params, { replace: true });
    }, 400);

    return () => clearTimeout(debounceRef.current);
  }, [filters, page, doSearch, setSearchParams]);

  const handleFilterChange = (key, value) => {
    setFilters((prev) => ({ ...prev, [key]: value }));
    setPage(1);
  };

  const resetFilters = () => {
    setFilters({
      state: '',
      suburb: '',
      postcode: '',
      propertyType: '',
      min_price: '',
      max_price: '',
      bedrooms: '',
      bathrooms: '',
      parkingSpaces: '',
    });
    setPage(1);
  };

  const rentals = results?.data || [];

  const getDisplayAddress = (r) => {
    const key = `${r.latitude},${r.longitude}`;

    if (addressCache[key]) return addressCache[key];

    if (r.latitude && r.longitude && !addressCache[key]) {
      getAddressFromCoords(r.latitude, r.longitude).then((addr) => {
        setAddressCache((prev) => ({ ...prev, [key]: addr }));
      });
    }

    return 'Loading address...';
  };

  return (
    <div className="search-page">

      {/* ================= SIDEBAR (UNCHANGED UI) ================= */}
      <div className="search-page__sidebar">
        <div className="filter-panel">

          <div className="filter-panel__header">
            <h2>Filters</h2>
            <button onClick={resetFilters}>Reset</button>
          </div>

          <div className="filter-section">
            <select
              value={filters.state}
              onChange={(e) => handleFilterChange('state', e.target.value)}
            >
              <option value="">All States</option>
              {states.map((s) => (
                <option key={s} value={s}>{s}</option>
              ))}
            </select>

            <select
              value={filters.propertyType}
              onChange={(e) =>
                handleFilterChange('propertyType', e.target.value)
              }
            >
              <option value="">All Types</option>
              {propertyTypes.map((t) => (
                <option key={t} value={t}>{t}</option>
              ))}
            </select>
          </div>

          <div className="filter-section">
            <input
              placeholder="Suburb"
              value={filters.suburb}
              onChange={(e) => handleFilterChange('suburb', e.target.value)}
            />

            <input
              placeholder="Postcode"
              value={filters.postcode}
              onChange={(e) => handleFilterChange('postcode', e.target.value)}
            />
          </div>

          <div className="filter-section">
            <input
              type="number"
              placeholder="Min Price"
              value={filters.min_price}
              onChange={(e) => handleFilterChange('min_price', e.target.value)}
            />

            <input
              type="number"
              placeholder="Max Price"
              value={filters.max_price}
              onChange={(e) => handleFilterChange('max_price', e.target.value)}
            />

            <input
              type="number"
              placeholder="Bedrooms"
              value={filters.bedrooms}
              onChange={(e) => handleFilterChange('bedrooms', e.target.value)}
            />

            <input
              type="number"
              placeholder="Bathrooms"
              value={filters.bathrooms}
              onChange={(e) => handleFilterChange('bathrooms', e.target.value)}
            />

            <input
              type="number"
              placeholder="Parking Spaces"
              value={filters.parkingSpaces}
              onChange={(e) => handleFilterChange('parkingSpaces', e.target.value)}
            />
          </div>

        </div>
      </div>

      {/* ================= RESULTS ================= */}
      <div className="search-page__results">

        <h1>
          {loading ? 'Searchingâ€¦' : `${rentals.length} results found`}
        </h1>

        {loading && <LoadingState />}
        {error && <ErrorState message={error} />}

        {!loading && rentals.length === 0 && (
          <EmptyState title="No results found" />
        )}

        {!loading && rentals.length > 0 && (
          <table className="results-table">
            <thead>
              <tr>
                <th>Address</th>
                <th>Suburb</th>
                <th>State</th>
                <th>Type</th>
                <th>Bed</th>
                <th>Bath</th>
                <th>Park</th>
                <th>Price</th>
              </tr>
            </thead>

            <tbody>
              {rentals.map((r) => (
                <tr key={r.id} onClick={() => navigate(`/rental/${r.id}`)}>
                  <td>{getDisplayAddress(r)}</td>
                  <td>{r.suburb || 'â€”'}</td>
                  <td>{r.state || 'â€”'}</td>
                  <td>{r.propertyType || 'â€”'}</td>
